ee:message.ee:set-payload:
%dw 2.0
output application/json
---
{
    id:          "CUST-" ++ (payload.sfdc_id default "UNKNOWN"),
    firstName:   payload.first_name default "",
    lastName:    payload.last_name  default "",
    email:       lower(payload.email_address default ""),
    phone:       if ((payload.phone_number default "") startsWith "+")
                     (payload.phone_number default "")
                 else if (payload.phone_number != null and payload.phone_number != "")
                     "+" ++ payload.phone_number
                 else null,
    status:      "active",
    createdDate: now() as String {format: "yyyy-MM-dd'T'HH:mm:ss'Z'"}
}
